	this.timeline.addTween(cjs.Tween.get(this.btnHome).wait(1).to({_off:false},0).wait(2));

	// btnAvanzar
	this.btnAvanzar = new lib.btnAvanzar();
	this.btnAvanzar.name = "btnAvanzar";
	this.btnAvanzar.setTransform(787.85,1680);
	this.btnAvanzar._off = true;
	new cjs.ButtonHelper(this.btnAvanzar, 0, 1, 2, false, new lib.btnAvanzar(), 3);

	this.timeline.addTween(cjs.Tween.get(this.btnAvanzar).wait(1).to({_off:false},0).wait(2));

	// btnPrevio
	this.btnPrevio = new lib.btnPrevio();
	this.btnPrevio.name = "btnPrevio";
	this.btnPrevio.setTransform(192.05,1705.95,1,1,0,0,0,38.1,27.1);
	this.btnPrevio._off = true;
	new cjs.ButtonHelper(this.btnPrevio, 0, 1, 2, false, new lib.btnPrevio(), 3);

