	// btnStop
	this.btnStop = new lib.btnStop();
	this.btnStop.name = "btnStop";
	this.btnStop.setTransform(701.45,1706.05,1,1,0,0,0,59.4,59.4);
	this.btnStop._off = true;
	new cjs.ButtonHelper(this.btnStop, 0, 1, 2, false, new lib.btnStop(), 3);

	this.timeline.addTween(cjs.Tween.get(this.btnStop).wait(1).to({_off:false},0).wait(2));

	// btnPausa
	this.btnPausa = new lib.btnPausa();
	this.btnPausa.name = "btnPausa";
	this.btnPausa.setTransform(543.45,1706.05,1,1,0,0,0,59.4,59.4);
	this.btnPausa._off = true;
	new cjs.ButtonHelper(this.btnPausa, 0, 1, 2, false, new lib.btnPausa(), 3);

	this.timeline.addTween(cjs.Tween.get(this.btnPausa).wait(1).to({_off:false},0).wait(2));

	// btnPlay
	this.btnPlay = new lib.btnPlay();
	this.btnPlay.name = "btnPlay";
	this.btnPlay.setTransform(392.85,1706.05,1,1,0,0,0,59.4,59.4);
	this.btnPlay._off = true;
	new cjs.ButtonHelper(this.btnPlay, 0, 1, 2, false, new lib.btnPlay(), 3);

	this.timeline.addTween(cjs.Tween.get(this.btnPlay).wait(1).to({_off:false},0).wait(2));

	// lblTiempo
	this.lblTiempo = new cjs.Text("0:01 ", "34px 'Arial'", "#FFFFFF");
	this.lblTiempo.name = "lblTiempo";
	this.lblTiempo.lineHeight = 45;
	this.lblTiempo.parent = this;
	this.lblTiempo.setTransform(122.1,1563.55);
